const express = require('express');
const { MongoClient, ObjectId } = require('mongodb');

const app = express();
app.use(express.json());

const MONGO_URI = process.env.MONGO_URI || 'mongodb://localhost:27017';
const DB_NAME = process.env.DB_NAME || 'queryservice';

let db;

MongoClient.connect(MONGO_URI, { useUnifiedTopology: true })
  .then(client => {
    db = client.db(DB_NAME);
    console.log('Connected to MongoDB');
  })
  .catch(err => {
    console.error('MongoDB connection error:', err);
    process.exit(1);
  });

function sanitizeQuery(query) {
  if (!query || typeof query !== 'object') {
    return {};
  }

  const allowedOperators = [
    '$eq', '$ne', '$gt', '$gte', '$lt', '$lte',
    '$in', '$nin', '$exists', '$type', '$regex',
    '$options', '$and', '$or', '$not', '$nor',
    '$all', '$elemMatch', '$size', '$mod',
    '$text', '$search', '$where'
  ];

  function processValue(value) {
    if (value && typeof value === 'object') {
      if (Array.isArray(value)) {
        return value.map(processValue);
      }

      const processed = {};
      for (const [key, val] of Object.entries(value)) {
        if (key.startsWith('$')) {
          if (allowedOperators.includes(key)) {
            processed[key] = processValue(val);
          }
        } else {
          processed[key] = processValue(val);
        }
      }
      return processed;
    }
    return value;
  }

  return processValue(query);
}

app.post('/api/query/:collection', async (req, res) => {
  try {
    const { collection } = req.params;
    const { filter = {}, projection = {}, sort = {}, limit = 100, skip = 0 } = req.body;

    const sanitizedFilter = sanitizeQuery(filter);
    
    const options = {};
    if (Object.keys(projection).length > 0) {
      options.projection = projection;
    }
    if (Object.keys(sort).length > 0) {
      options.sort = sort;
    }
    options.limit = Math.min(parseInt(limit) || 100, 1000);
    options.skip = parseInt(skip) || 0;

    const results = await db.collection(collection)
      .find(sanitizedFilter, options)
      .toArray();

    res.json({
      success: true,
      count: results.length,
      data: results
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
});

